class Solution {
    public int findTheLongestSubstring(String s) {
        int[] seen = new int[32];
        Arrays.fill(seen, -1);
        seen[0] = 0;
        int maxLen = 0, prefix = 0;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (c == 'a') prefix ^= 1 << 0;
            else if (c == 'e') prefix ^= 1 << 1;
            else if (c == 'i') prefix ^= 1 << 2;
            else if (c == 'o') prefix ^= 1 << 3;
            else if (c == 'u') prefix ^= 1 << 4;
            if (seen[prefix] != -1) maxLen = Math.max(maxLen, i + 1 - seen[prefix]);
            else seen[prefix] = i + 1;
        }
        return maxLen;
    }
}
